INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('police-8b7f1efc-moex-00557', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '在警察公共政策分析議題中，有以市場機制（解決問題）為中心的政策分析（mechanism-centered policyanalysis）取向，這其中包含政府失靈（governmentfailure）的現象。Weimer&Vining曾提 出造成政府失靈的原因，下列何者不是他們所提出的問題？', '["直接民主", "代議政府", "官僚體系", "集權政府"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "ba3a434a0a92", "answer_pdf_sha1": "903975beb430", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1110", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00558', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', 'Elmore（1978）將政策執行的組織研究分為四種模式：系統管理模式（systemsmanagementmodel）、 官僚過程模式（bureaucraticprocessmodel）、組織發展模式（organizationaldevelopmentmodel）、 衝突協調模式（conflictandbargainingmodel），若用上述四模式與警察機關組織文化相呼應，下 列敘述何者正確？', '["以官僚過程模式的思維，警察機關發展出以破案為目標及績效掛帥的組織文化是可以預期的", "以組織發展模式的思維，行政人員對例行承辦工作的熟悉，架空了來自長官的控制力量，警察 組織基層承辦人與業者的掛勾可能在此情況下產生", "以系統管理模式的思維，社區警政要求警察管理幹部視基層為內在顧客，擴大參與決策，尊重 基層意見", "以衝突協調模式的思維，警察組織中的刑事警察與制服警察的衝突妥協，就是屬於此模式"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "ba3a434a0a92", "answer_pdf_sha1": "903975beb430", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1110", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00559', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', 'Fischer 提出公共政策的批判評估（critical evaluation of public policy）四種分析，包含技術印證 （technicalverification）、情境確證（situationalvalidation）、系統驗證（systemvindication）和理 性的社會選擇（rationalsocialchoice）。若將上述四種分析應用於警察政策評估，下列敘述何者 正確？', '["測量警力之運用是否有效達成目標，此即「系統驗證」的政策評估", "社區治安問題的認定應重視社區民眾的需求與意見，此即「情境確證」的政策評估", "將警察政策評估提升至總體評估的層次，此即「理性的社會選擇」的政策評估", "警察在維持秩序與保障人權之間的價值澄清與組合，此即「技術印證」的政策評估"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "ba3a434a0a92", "answer_pdf_sha1": "903975beb430", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1110", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00560', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', 'Stone對於政策分析的觀點與三部分的架構，下列敘述何者錯誤？', '["許多的政策決定可用理性模式解釋", "目標指的是政策尋求的價值", "問題指的是目標與現狀的差異", "解決方案指的是處理政策問題的工具"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "ba3a434a0a92", "answer_pdf_sha1": "903975beb430", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1110", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00561', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', 'Peel爵士在1829年創立了第一個現代化警察組織之後，警察成為一種專門職業，其創立地點在 下列何處？', '["法國巴黎", "德國漢堡", "瑞典斯德哥爾摩", "英國倫敦"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "ba3a434a0a92", "answer_pdf_sha1": "903975beb430", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1110", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00562', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', 'Moore等人提出，社區警政有四大工作實務內涵，下列何者錯誤？', '["指揮集權化", "社區犯罪預防", "增加警察責任心與成就感", "重組巡邏活動"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "ba3a434a0a92", "answer_pdf_sha1": "903975beb430", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1110", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00563', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', 'Reppetto曾指出警察機關對付犯罪必須靠嚇阻、犯罪偵查及犯罪人的逮捕三項策略來達成。而三 項策略也必須靠下列四項勤務活動來達成，下列何者錯誤？', '["警力遍在（Omnipresence）", "守勢巡邏（DefensivePatrol）", "立即反應（PromptResponse）", "密集偵查（Follow-UpInvestigation）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "ba3a434a0a92", "answer_pdf_sha1": "903975beb430", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1110", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00564', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', 'Felson & Clarke認為「機會」是所有犯罪行為的根本，並列舉出10項機會原理，說明機會如何 形塑犯罪行為。下列所述各項原理何者錯誤？', '["減少機會，會導致犯罪轉移的發生", "犯罪機會，受個人日常活動的影響", "犯罪機會可因外力介入而減少", "致力減少犯罪機會，可擴大犯罪數量的降幅"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "ba3a434a0a92", "answer_pdf_sha1": "903975beb430", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1110", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00565', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '在警察角色的變遷過程中，警察由傳統秩序維持者轉換到具有社區警政之特點，下列敘述何者錯誤？', '["警察的工作範疇不再是以犯罪為中心，也強調為民服務", "警察對於與民眾生活息息相關的治安與非治安案件都加以重視", "警政重點逐漸由預防式（proactive）警政，走向反應式（reactive）警政", "警察機關必須在結構上改進，同時鼓勵創新，提倡參與式管理，才能有效因應社區警政要求"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "ba3a434a0a92", "answer_pdf_sha1": "903975beb430", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1110", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00566', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '少年事件處理法於2019年的修正，為自1997年以來最大幅度的修正，也是與世界兒少司法權益 潮流接軌的重要里程碑。對本次修法重點的敘述，下列何者錯誤？', '["廢除觸法兒童準用少年事件處理法之規定", "建置曝險少年司法先行機制", "尊重少年主體權及保障程序權", "引進少年修復式機制"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "ba3a434a0a92", "answer_pdf_sha1": "903975beb430", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1110", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL)
